qry:select.qry:xquery:
for $r in sql('SELECT 
t0.oi_variable, 
t0.c_variable, 
t0.d_variable,   
t0.c_tipo_dato, 
t0.c_externo,
t0.c_tipo_variable
FROM 
LIQ09_VARIABLES AS t0
WHERE 
{%? (#SOURCE:@c_tipo_variable!='')
	{% t0.c_tipo_variable = {#SOURCE:@c_tipo_variable} %}
	{% 1 = 1 %}
%}  
and
{%? (#SOURCE:@oi_variable!='')
	{% t0.oi_variable = {#SOURCE:@oi_variable} %}
	{% 1 = 1 %}
%}				
{%? (#SOURCE:@variable!='')	
	{% 
		AND (CONTAIN(t0.d_variable, {#SOURCE:@variable}) OR
		CONTAIN(t0.c_variable, {#SOURCE:@variable}) )
	%}
	{% %} 
%}
ORDER BY
{%? (#SOURCE:@ATRIB_ORDEN1!='')	{% {%=#SOURCE:@ATRIB_ORDEN1%} {%? (#SOURCE:@ORDEN1!='') {% {%=#SOURCE:@ORDEN1%}, %} {% ASC, %}	%} %} {% %} %}
oi_variable ASC')/ROWS/ROW
